import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import './ProfilePage.css';

const ProfilePage = () => {
  const { user, setUser, logout } = useAuth();
  const navigate = useNavigate();
  const [isEditing, setIsEditing] = useState(false);
  const [formData, setFormData] = useState({
    fullName: user?.fullName || '',
    bio: user?.bio || ''
  });
  const [uploading, setUploading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [toast, setToast] = useState(null);

  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  if (!user) {
    navigate('/');
    return null;
  }

  const showToast = (message, type = 'success') => {
    setToast({ message, type });
  };

  const handleInputChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handlePictureUpload = async (e) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setUploading(true);
    try {
      const fd = new FormData();
      fd.append('file', file);

      const response = await axios.post(
        `${process.env.REACT_APP_API_URL || 'http://localhost:5000'}/api/profile/${user._id}/picture`,
        fd,
        { headers: { 'Content-Type': 'multipart/form-data' } }
      );

      setUser(response.data.user);
      showToast('Profile picture updated!');
    } catch (error) {
      console.error('Upload error:', error);
      showToast('Failed to upload picture', 'error');
    } finally {
      setUploading(false);
    }
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      const response = await axios.put(
        `${process.env.REACT_APP_API_URL || 'http://localhost:5000'}/api/profile/${user._id}`,
        formData
      );

      setUser(response.data);
      setIsEditing(false);
      showToast('Profile updated successfully!');
    } catch (error) {
      console.error('Save error:', error);
      showToast('Failed to update profile', 'error');
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="profile-page">
      <div className="profile-card">
        <div className="profile-avatar-wrapper">
          {user.profilePicture ? (
            <img 
              src={user.profilePicture} 
              alt="Profile"
              className="profile-avatar-img"
            />
          ) : (
            <div className={`profile-avatar-placeholder ${user.gender?.toLowerCase()}`}>
              {user.nickname?.charAt(0).toUpperCase()}
            </div>
          )}
          <label className="profile-upload-btn">
            {uploading ? '⏳' : '📷'}
            <input
              type="file"
              accept="image/*"
              onChange={handlePictureUpload}
              disabled={uploading}
            />
          </label>
        </div>

        <h2 className="profile-nickname">{user.nickname}</h2>
        <p className={`profile-gender-tag ${user.gender?.toLowerCase()}`}>
          {user.gender === 'Male' ? '👨' : '👩'} {user.gender}
        </p>

        {isEditing ? (
          <div className="profile-edit-form">
            <label>Full Name</label>
            <input
              type="text"
              name="fullName"
              value={formData.fullName}
              onChange={handleInputChange}
              placeholder="Enter your full name"
            />
            <label>Bio</label>
            <textarea
              name="bio"
              value={formData.bio}
              onChange={handleInputChange}
              placeholder="Tell us about yourself..."
              rows="4"
            />
            <div className="profile-actions">
              <button
                onClick={handleSave}
                disabled={saving}
                className="profile-btn-primary"
              >
                {saving ? 'Saving...' : '✅ Save'}
              </button>
              <button
                onClick={() => setIsEditing(false)}
                disabled={saving}
                className="profile-btn-secondary"
              >
                Cancel
              </button>
            </div>
          </div>
        ) : (
          <>
            {user.fullName && (
              <p className="profile-fullname">{user.fullName}</p>
            )}
            {user.bio && (
              <p className="profile-bio">{user.bio}</p>
            )}
            <p className="profile-meta">
              {user.isFullAccount ? '✅ Full Account' : '👤 Guest User'}
            </p>
            <p className="profile-meta-last">
              📹 Video calls used: {user.freeCallsUsed || 0}
            </p>
            <div className="profile-actions">
              <button
                onClick={() => setIsEditing(true)}
                className="profile-btn-primary"
              >
                ✏️ Edit Profile
              </button>
              <button
                onClick={() => { logout(); navigate('/'); }}
                className="profile-btn-danger"
              >
                🚪 Logout
              </button>
            </div>
          </>
        )}
      </div>

      {toast && (
        <div className={`profile-toast ${toast.type}`}>
          {toast.message}
        </div>
      )}
    </div>
  );
};

export default ProfilePage;
